// ===== 레트로 타자기 오프닝 + 타자 폭발 파티클 렌더링 =====
const canvas = document.querySelector('canvas');
const ctx = canvas.getContext('2d', { alpha: false });

let particles = [];
let mouse = { x: -1000, y: -1000, radius: 100 };
const isMobile = window.innerWidth < 768;

const LOGO_DATA = 'data:image/png;base64,';

// === 애니메이션 상태 변수 ===
let startTime = 0;
let explodeStartTime = 0;
// 타자가 쳐지는 시간 (동적으로 계산됨)
let phaseTypingReal = 0;
// 글씨를 다 치고 확인하는 여운 (1초)
const PHASE_HOLD = 1000;
// 터지고 모이는 총 애니메이션 시간 (3초)
const PHASE_EXPLODE = 3000;
let animationState = 'intro';
let typeTimings = null;
let bottomTextStarted = false;
let bottomTextTimer = 0;

function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
}
resizeCanvas();

window.addEventListener('resize', () => {
    resizeCanvas();
    if (logoImageLoaded) initParticles();
});

// 마우스 이벤트
document.addEventListener('mousemove', (e) => { mouse.x = e.clientX; mouse.y = e.clientY; });
document.addEventListener('mouseleave', () => { mouse.x = -1000; mouse.y = -1000; });
document.addEventListener('touchstart', (e) => { if(e.touches.length) { mouse.x = e.touches[0].clientX; mouse.y = e.touches[0].clientY; } }, { passive: true });
document.addEventListener('touchmove', (e) => { if(e.touches.length) { mouse.x = e.touches[0].clientX; mouse.y = e.touches[0].clientY; } }, { passive: true });
document.addEventListener('touchend', () => { mouse.x = -1000; mouse.y = -1000; }, { passive: true });

class Particle {
    constructor(hugeX, hugeY, size, color) {
        this.originX = hugeX;
        this.originY = hugeY;
        
        // 시작점은 타자기 텍스트의 좌표에서 가져오기 전 비워둠
        this.startX = 0;
        this.startY = 0;
        this.x = -1000;
        this.y = -1000;
        
        this.baseSize = size;
        this.size = size;
        this.color = color;
        this.vx = 0;
        this.vy = 0;
        this.friction = 0.8;
        this.spring = 0.15; 
        
        this.randomMod = Math.random();
    }
    
    explode() {
        let centerX = window.innerWidth / 2;
        let centerY = window.innerHeight / 2;
        let dx = this.startX - centerX;
        let dy = this.startY - centerY;
        
        // 너무 작위적인 수학적 나선형 모양("나는 나선형입니다!")을 부수고 거친 카오스 폭발로 변경
        
        // 1. Y축 보정을 조금 더 자연스럽게(3배) 변경하여 억지스럽지 않은 원형 밸런스 유지
        let angle = Math.atan2(dy * 3.0, dx); 
        
        // 2. 대열을 만들던 '거리 기반 나선형 꼬임 공식' 완전 삭제!
        // 대신 전체적으로 비스듬하게 뻗어나가는(회전하는 듯한 세련된 뉘앙스) 스큐(Skew)만 살짝 줌
        angle += 0.8; 
        
        // 3. 패턴을 완전히 분쇄하는 자비 없는 난수 확산!
        // 궤도가 눈에 보이지 않도록, 화약이 터지듯 불규칙하고 와일드하게 사방으로 찢어발김
        angle += (this.randomMod - 0.5) * 4.0; 
        
        // 4. 모니터 바깥을 시원하게 뚫고 나가는 파워풀 블래스트 (유지)
        // 화면 해상도에 맞춰서 폭발력을 스케일링 (모바일에서 우주 끝까지 날아가 돌아오지 못하고 조립이 꼬이는 현상 방지)
        let scaleFactor = Math.max(0.3, window.innerWidth / 1920);
        let force = (this.randomMod * 180 + 80) * scaleFactor;
        
        this.vx = Math.cos(angle) * force;
        this.vy = Math.sin(angle) * force;
    }

    update() {
        let targetX = this.originX;
        let targetY = this.originY;
        let currentSpring = this.spring;
        let currentFriction = this.friction;

        if (animationState === 'explode') {
            let explodeElapsed = Date.now() - explodeStartTime;
            let progress = Math.min(explodeElapsed / PHASE_EXPLODE, 1.0);
            
            let dropPhase = Math.min(progress * 2.0, 1.0); 
            let risePhase = Math.max(0, (progress - 0.5) * 2.0); 

            if (progress < 0.5) {
                // 초반(0~50%): 바닥에 쌓이지 않고 모니터 밖으로 시원하게 퍼지도록 마찰 최소화
                currentFriction = 0.98; 
                currentSpring = 0; 
                
                // 유저 피드백 반영: 조립 전에 탱탱볼처럼 통통 튀며 빙빙 도는 느낌(Swirl) 원척 삭제!
                // 억지스러운 곡선이나 회전력을 없애고, 파편들이 깨끗하게 직선으로 터져나가게 구조화함.
                
                // 중력(떨어짐) 연출 완전히 삭제. 
                // 이제 파티클들은 어디론가 쏟아져 내리지 않고, 터진 방향 그대로 무중력 우주처럼 끝없이 뻗어 나갑니다.
            } else {
                // 탱글거리는 탄성(고무줄) 효과 완전 삭제. 
                currentSpring = 0; 
                currentFriction = 0.75; // 기존 우주로 날아가던 관성에 급브레이크
                
                // 0.5 ~ 0.8 진행도 구간 사이에 도트별로 제자리로 돌아가는 타이밍을 흩어놓음
                let mySnapTime = 0.5 + this.randomMod * 0.3; 
                
                if (progress > mySnapTime) {
                    let oDx = targetX - this.x;
                    let oDy = targetY - this.y;
                    let snapPower = (progress - mySnapTime) * 3.0; // 시간 단위로 폭증하는 자성력
                    
                    // 유저 요청 반영: 미사일처럼 대각선으로 날아가는 공격적인 모션 제거
                    // 대신, 상하/좌우(Orthogonal) 직선으로만 움직이면서 90도로 꺾여 자리를 찾아가는 사이버틱한 데이터 라우팅 방식 적용
                    if (!this.routingAxis) {
                        this.routingAxis = Math.abs(oDx) > Math.abs(oDy) ? 'x' : 'y';
                    }

                    if (this.routingAxis === 'x') {
                        this.vx += oDx * snapPower * 0.25;
                        this.vy *= 0.1; // 간섭을 차단하여 완벽한 가로(X) 직선 유지
                        
                        // x축 근접 시 90도 꺾어서 y축으로 진입
                        if (Math.abs(oDx) < 20) this.routingAxis = 'y';
                    } else {
                        this.vy += oDy * snapPower * 0.25;
                        this.vx *= 0.1; // 간섭을 차단하여 완벽한 세로(Y) 직선 유지
                        
                        // y축 근접 시 90도 꺾어서 x축으로 진입
                        if (Math.abs(oDy) < 20) this.routingAxis = 'x';
                    }
                    
                    // 목표점 근방 도달 판별 (모바일 오버슈팅으로 인해 좌표를 지나치지 않도록 히트박스를 살짝 여유있게 잡음)
                    if (Math.abs(oDx) < 8 && Math.abs(oDy) < 8) {
                        this.x = targetX;
                        this.y = targetY;
                        this.vx = 0; // 흔들림, 잔상 절대 방지
                        this.vy = 0;
                        this.routingAxis = null;
                    }
                }
            }

            // 바닥에 도트가 쓰레기나 모래처럼 고이게 만들던 바운더리 차단(벽) 로직 완벽 삭제 상태 유지!
            // 이렇게 하면 중력을 받아 모니터 밑으로 시원하게 사라졌다가, 후반부에 보이지 않는 심연에서부터 스크린 중앙으로 텐션 있게 빨려들어옴.


        } 
        else if (animationState === 'interactive') {
            targetX = this.originX; 
            targetY = this.originY;
            
            // 탱글탱글하게 원래 좌표로 튕겨 돌아가려는 성질을 거의 없앰 (극미세 수치)
            // 딱딱한 원형이나 수학적 경계를 유지하지 않고 연기나 모래알처럼 '우아하게 퍼지도록'
            currentSpring = 0.007; 
            currentFriction = 0.94; // 관성(미끄러짐) 대폭 증가

            if (mouse.x !== -1000) {
                // 본래 좌표가 아니라 현재 입자의 좌표(this.x)를 기준으로 반응하게 하여
                // 원형 렌즈의 채도 상승 뭉침이나 억지스러운 형태 유지를 완전히 분쇄함
                let dx = this.x - mouse.x; 
                let dy = this.y - mouse.y;
                let distance = Math.sqrt(dx * dx + dy * dy);
                
                let maxDist = window.innerWidth < 768 ? 150 : 450; // 모바일 터치 시에는 밀어내는 범위를 화면에 맞게 축소
                
                if (distance < maxDist && distance > 0) {
                    // 입자들을 한 곳에 몰아넣어 밝은 경계선이 생기는 문제를 없애도록
                    // 강제 이동이 아닌 '입김을 불듯 아주 부드럽고 지속적인 속력(Velocity)'만 부여
                    let force = Math.pow((maxDist - distance) / maxDist, 2.0); // 끝으로 갈수록 극도로 자연스럽게 힘이 빠짐
                    let pushFactor = 3.5; // 날카롭지 않고 우아하게 밀려나는 정도
                    
                    this.vx += (dx / distance) * force * pushFactor;
                    this.vy += (dy / distance) * force * pushFactor;
                }
            }
        }

        this.vx += (targetX - this.x) * currentSpring;
        this.vy += (targetY - this.y) * currentSpring;
        this.vx *= currentFriction;
        this.vy *= currentFriction;
        this.x += this.vx;
        this.y += this.vy;
    }
    
    draw() {
        if (this.x === -1000) return; // 폭발 전에는 숨김
        ctx.fillStyle = this.color;
        let s = Math.max(1.0, this.size * 1.8);
        ctx.fillRect(this.x - s/2, this.y - s/2, s, s);
    }
}

let logoImageLoaded = false;
const img = new Image();
img.src = LOGO_DATA;
img.onload = () => {
    logoImageLoaded = true;
    initParticles();
    startTime = Date.now();
    animate();
};

function prepareExplosionFromText() {
    const offCanvas = document.createElement('canvas');
    const offCtx = offCanvas.getContext('2d', { alpha: true });
    offCanvas.width = canvas.width;
    offCanvas.height = canvas.height;
    
    // 폭발 직전 타자 텍스트와 완벽히 똑같은 형태 그리기
    const textLines = ["HELLO.", "I AM WORLDVIEW."];
    // 시크한 버질 아블로 헬베티카 스타일
    const fontSize = isMobile ? window.innerWidth * 0.08 : 70;
    offCtx.font = `900 ${fontSize}px "Helvetica Neue", Helvetica, Arial, sans-serif`;
    offCtx.fillStyle = '#ff0000';
    offCtx.textAlign = 'left';
    offCtx.textBaseline = 'top';

    let maxWidth = Math.max(offCtx.measureText(textLines[0]).width, offCtx.measureText(textLines[1]).width);
    let tX = (offCanvas.width - maxWidth) / 2;
    let tY = (offCanvas.height - (fontSize * 2.5)) / 2;

    offCtx.fillText(textLines[0], tX, tY);
    offCtx.fillText(textLines[1], tX, tY + fontSize * 1.2);

    const imgData = offCtx.getImageData(0, 0, offCanvas.width, offCanvas.height).data;
    const validPixels = [];
    
    // 텍스트에서 붉은 영역 픽셀 위치 스캔
    for (let y = 0; y < offCanvas.height; y += 4) {
        for (let x = 0; x < offCanvas.width; x += 4) {
            const ix = (y * offCanvas.width + x) * 4;
            if (imgData[ix + 3] > 128) {
                validPixels.push({x: x, y: y});
            }
        }
    }

    // 각 파티클들이 이제 방금 쓴 텍스트 좌표들에서 쏟아지게 시작점 할당!
    for (let p of particles) {
        if (validPixels.length > 0) {
            let rndP = validPixels[Math.floor(Math.random() * validPixels.length)];
            p.startX = rndP.x + (Math.random() * 4 - 2); 
            p.startY = rndP.y + (Math.random() * 4 - 2);
        } else {
            p.startX = canvas.width / 2;
            p.startY = canvas.height / 2;
        }
        p.x = p.startX;
        p.y = p.startY;
        p.explode();
    }
}

function initParticles() {
    particles = [];
    const offCanvas = document.createElement('canvas');
    const offCtx = offCanvas.getContext('2d');
    
    const hugeLogoScale = isMobile ? 0.95 : 0.65;
    
    let hugeWidth = canvas.width * hugeLogoScale;
    let hugeHeight = hugeWidth * (img.naturalHeight / img.naturalWidth);
    
    offCanvas.width = hugeWidth;
    offCanvas.height = hugeHeight;
    offCtx.drawImage(img, 0, 0, hugeWidth, hugeHeight);
    
    const imageData = offCtx.getImageData(0, 0, Math.floor(hugeWidth), Math.floor(hugeHeight));
    const data = imageData.data;
    
    const offsetX = (canvas.width - hugeWidth) / 2;
    const offsetY = (canvas.height - hugeHeight) / 2;
    
    const gap = isMobile ? 6 : 8; 
    const particleSize = isMobile ? 1.5 : 2.5;
    
    let w = Math.floor(hugeWidth);
    let h = Math.floor(hugeHeight);
    let g = Math.floor(gap);

    for (let y = 0; y < hugeHeight; y += gap) {
        for (let x = 0; x < hugeWidth; x += gap) {
            let tx = Math.floor(x);
            let ty = Math.floor(y);
            const index = (ty * w + tx) * 4;
            const r = data[index];
            const g = data[index + 1];
            const b = data[index + 2];
            const a = data[index + 3];
            
            if (a > 128) {
                let isEdge = false;
                if (tx - g >= 0 && tx + g < w && ty - g >= 0 && ty + g < h) {
                    let ti = ((ty - g) * w + tx) * 4 + 3;
                    let bi = ((ty + g) * w + tx) * 4 + 3;
                    let li = (ty * w + (tx - g)) * 4 + 3;
                    let ri = (ty * w + (tx + g)) * 4 + 3;
                    if (data[ti] < 128 || data[bi] < 128 || data[li] < 128 || data[ri] < 128) {
                        isEdge = true; 
                    }
                } else {
                    isEdge = true; 
                }

                let color;
                if (isEdge || a < 240) {
                    // 외곽
                    color = `rgb(${Math.floor(r * 0.4)}, 0, 0)`; 
                } else {
                    // 코어 컬러는 주신 원본 RGB 컬러를 오차 1도 없이 100% 퓨어하게 매핑 (음영은 동적으로 덮음)
                    color = `rgb(${r}, ${g}, ${b})`; 
                }

                let originX = x + offsetX;
                let originY = y + offsetY;
                particles.push(new Particle(originX, originY, particleSize, color));
            }
        }
    }
}

function animate() {
    ctx.fillStyle = '#000000';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    
    let elapsed = Date.now() - startTime;

    if (animationState === 'intro') {
        const textLines = ["HELLO.", "I AM WORLDVIEW."];
        const fullText = textLines[0] + textLines[1];
        
        // 사람이 치는 듯한 실제적인 타자 리듬 (Burst Typing 방식)
        if (!typeTimings) {
            typeTimings = [];
            let acc = 0;
            let burstCount = 0; // 타다닥! 하고 연속으로 치는 글자 수
            
            for(let i=0; i<fullText.length; i++) {
                let delay = 0;
                let char = fullText[i];
                
                // 마침표나 스페이스에서는 완전히 한 템포 쉼
                if (char === '.' || char === ' ') {
                    delay = 300 + Math.random() * 250; 
                    burstCount = 0; 
                } else if (burstCount > 0) {
                    // 몰아칠 때는 인간의 경이로운 연타 속도 (30~80ms)
                    delay = 30 + Math.random() * 50; 
                    burstCount--;
                } else {
                    // 단어를 시작할 때 약간 머뭇 (100~200ms)
                    delay = 100 + Math.random() * 100; 
                    // 다음 2~4글자는 미친듯이 빠르게 몰아침
                    burstCount = Math.floor(Math.random() * 3) + 2; 
                }
                
                acc += delay;
                typeTimings.push(acc);
            }
            phaseTypingReal = acc; // 억지로 늘리지 않고, 사람 손이 친 진짜 시간을 전체 시간으로 지정
        }
        
        let charsToShow = 0;
        for(let i=0; i<typeTimings.length; i++) {
            if (elapsed > typeTimings[i]) charsToShow = i + 1;
        }

        let line1Chars = textLines[0].length;
        
        // 1. 투박한 타자기 느낌을 위해 깜빡이는 커서 '_' 추가
        let cursorBlink = (Math.floor(Date.now() / 150) % 2 === 0) ? "_" : " ";
        let showLine1 = textLines[0].substring(0, charsToShow);
        let showLine2 = "";
        
        if (charsToShow <= line1Chars) {
            showLine1 += cursorBlink; 
        } else {
            showLine2 = textLines[1].substring(0, charsToShow - line1Chars) + cursorBlink; 
        }

        // 버질 아블로 스타일의 깔끔하고 강건한 헬베티카 산세리프 폰트
        const fontSize = isMobile ? window.innerWidth * 0.08 : 70;
        ctx.font = `900 ${fontSize}px "Helvetica Neue", Helvetica, Arial, sans-serif`;
        
        // 2. 가로 불안감 (Glitch/Jitter): 글자 전체가 미세하게 가로로 흔들거림
        let jitterX = 0;
        if (Math.random() < 0.3) {
            jitterX = (Math.random() - 0.5) * 8; 
        }

        let maxWidth = Math.max(ctx.measureText(textLines[0]).width, ctx.measureText(textLines[1]).width);
        let tX = (canvas.width - maxWidth) / 2 + jitterX;
        let tY = (canvas.height - (fontSize * 2.5)) / 2;

        // 3. 가독성을 확보한 선명하고 쨍한 발광 효과
        ctx.fillStyle = '#ff0000'; // 퓨어 레드
        ctx.shadowColor = '#ff0000';
        ctx.shadowBlur = 15; // 글씨를 덮어버리지 않게 블러 축소
        ctx.textAlign = 'left';
        ctx.textBaseline = 'top';

        // 1차 렌더링: 글로우(불빛) 베이스 깔기
        ctx.fillText(showLine1, tX, tY);
        ctx.fillText(showLine2, tX, tY + fontSize * 1.2);
        
        // 2차 렌더링: 블러를 끄고 글자를 그 위에 한 번 더 날카롭게 찍어내서 엄청 또렷하게 만듦
        ctx.shadowBlur = 0; 
        ctx.shadowColor = 'transparent';
        ctx.fillText(showLine1, tX, tY);
        ctx.fillText(showLine2, tX, tY + fontSize * 1.2);

        // 4. 가로로 찌그러지고 찢어지는듯한 불안한 글리치 (가독성을 위해 아주 가끔, 약하게만 발동)
        if (Math.random() < 0.04) {
            let sliceY = tY + Math.random() * (fontSize * 2.5);
            let sliceH = Math.random() * 8 + 2; 
            let shiftX = (Math.random() - 0.5) * 15; // 너무 찢어지지 않도록 폭 축소
            // 캔버스 가로 영역을 복사해서 옆으로 밀어서 그리기 (아날로그 VCR 느낌)
            ctx.drawImage(canvas, 
                0, sliceY, canvas.width, sliceH,
                shiftX, sliceY, canvas.width, sliceH 
            );
        }

        // 전체 화면 위에 낡고 섬뜩한 CRT 모니터 가로줄(Scanline) 필터 씌우기 (글씨가 잘 보이게 투명도 대폭 완화)
        ctx.fillStyle = 'rgba(0, 0, 0, 0.15)';
        for (let y = 0; y < canvas.height; y += 4) {
            ctx.fillRect(0, y, canvas.width, 1);
        }

        if (elapsed > phaseTypingReal + PHASE_HOLD) {
            animationState = 'explode';
            explodeStartTime = Date.now();
            prepareExplosionFromText(); // 텍스트에서 파티클 추출하고 폭발!
        }
    } else {
        if (animationState === 'explode') {
            let explodeElapsed = Date.now() - explodeStartTime;
            if (explodeElapsed > PHASE_EXPLODE) {
                animationState = 'interactive';
            }
        }

        // 파티클 로고가 완전히 형성되고 안정을 찾았을 때 타이핑 시작!
        if (animationState === 'interactive' && !bottomTextStarted) {
            bottomTextStarted = true;
            bottomTextTimer = Date.now();
        }

        // 하단 커밍순 텍스트 자바스크립트 버스트 타이핑 이펙트 처리
        if (bottomTextStarted) {
            const bottomTarget = "COMING SOON.";
            let elapsedText = Date.now() - bottomTextTimer;
            let charsToShow = Math.floor(elapsedText / 120); // 1글자당 120ms
            
            if (charsToShow > bottomTarget.length) {
                charsToShow = bottomTarget.length;
            }
            
            let displayStr = bottomTarget.substring(0, charsToShow);
            let cursorBlink = (Math.floor(Date.now() / 200) % 2 === 0) ? "_" : " ";
            let el = document.getElementById('bottom-text');
            
            if (charsToShow < bottomTarget.length) {
                displayStr += cursorBlink;
            } else {
                displayStr = bottomTarget;
                
                // 다 써지고 난 뒤 약 0.5초 뒤, 지직지직 네온사인이 켜지는 클래스 부여!
                if (el && elapsedText > (bottomTarget.length * 120) + 500) {
                    el.classList.add('neon-on');
                }
            }
            
            // DOM 접근해서 렌더링
            if (el && el.innerText !== displayStr) {
                el.innerText = displayStr;
                el.setAttribute('data-text', displayStr); // 가로 찢어짐 글리치를 위한 CSS attr 연결
            }
        }

        for (let i = 0; i < particles.length; i++) {
            particles[i].update();
            particles[i].draw();
        }
    }
    requestAnimationFrame(animate);
}
